index 00efd3c0eb72..9b2337c7466c 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5668,6 +5668,150 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   return true;
 }

+/// Try to simplify a switch whose condition is a call to llvm.ucmp or llvm.scmp.
+/// The cmp intrinsic returns -1 (less than), 0 (equal), or 1 (greater than).
+/// If the switch partitions these values into two groups, convert to an icmp.
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  auto *II = dyn_cast<IntrinsicInst>(Cond);
+  if (!II)
+    return false;
+  
+  Intrinsic::ID ID = II->getIntrinsicID();
+  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
+    return false;
+  
+  Type *RetTy = II->getType();
+  if (!RetTy->isIntegerTy())
+    return false;
+  
+  BasicBlock *DestA = nullptr;
+  BasicBlock *DestB = nullptr;
+  SmallVector<ConstantInt *, 4> CasesA;
+  SmallVector<ConstantInt *, 4> CasesB;
+  
+  for (auto Case : SI->cases()) {
+    BasicBlock *Dest = Case.getCaseSuccessor();
+    ConstantInt *Val = Case.getCaseValue();
+    if (!DestA) {
+      DestA = Dest;
+      CasesA.push_back(Val);
+    } else if (Dest == DestA) {
+      CasesA.push_back(Val);
+    } else if (!DestB) {
+      DestB = Dest;
+      CasesB.push_back(Val);
+    } else if (Dest == DestB) {
+      CasesB.push_back(Val);
+    } else {
+      return false;
+    }
+  }
+  
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  bool DefaultToA = (DefaultDest == DestA);
+  bool DefaultToB = (DestB && DefaultDest == DestB);
+  if (!DestB) {
+    DestB = DefaultDest;
+    DefaultToB = true;
+  } else if (!DefaultToA && !DefaultToB) {
+    return false;
+  }
+  
+  if (!DestB)
+    return false;
+  
+  bool HasMinusOneInA = false, HasZeroInA = false, HasOneInA = false;
+  bool HasMinusOneInB = false, HasZeroInB = false, HasOneInB = false;
+  
+  for (auto *C : CasesA) {
+    int64_t V = C->getSExtValue();
+    if (V == -1) HasMinusOneInA = true;
+    else if (V == 0) HasZeroInA = true;
+    else if (V == 1) HasOneInA = true;
+  }
+  for (auto *C : CasesB) {
+    int64_t V = C->getSExtValue();
+    if (V == -1) HasMinusOneInB = true;
+    else if (V == 0) HasZeroInB = true;
+    else if (V == 1) HasOneInB = true;
+  }
+  
+  if (DefaultToA) {
+    if (!HasMinusOneInB) HasMinusOneInA = true;
+    if (!HasZeroInB) HasZeroInA = true;
+    if (!HasOneInB) HasOneInA = true;
+  }
+  if (DefaultToB) {
+    if (!HasMinusOneInA) HasMinusOneInB = true;
+    if (!HasZeroInA) HasZeroInB = true;
+    if (!HasOneInA) HasOneInB = true;
+  }
+  
+  CmpInst::Predicate Pred;
+  BasicBlock *TrueDest, *FalseDest;
+  bool IsSigned = CmpIntrinsic::isSigned(ID);
+  
+  if (HasMinusOneInA && HasZeroInA && HasOneInB &&
+      !HasMinusOneInB && !HasZeroInB) {
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (HasMinusOneInB && HasZeroInB && HasOneInA &&
+             !HasMinusOneInA && !HasZeroInA) {
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if (HasMinusOneInA && !HasZeroInA && !HasOneInA &&
+             HasZeroInB && HasOneInB && !HasMinusOneInB) {
+    Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if (HasMinusOneInB && !HasZeroInB && !HasOneInB &&
+             HasZeroInA && HasOneInA && !HasMinusOneInA) {
+    Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else if (HasZeroInA && !HasMinusOneInA && !HasOneInA &&
+             HasMinusOneInB && HasOneInB && !HasZeroInB) {
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if (HasZeroInB && !HasMinusOneInB && !HasOneInB &&
+             HasMinusOneInA && HasOneInA && !HasZeroInA) {
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  } else {
+    return false;
+  }
+  
+  Value *LHS = II->getOperand(0);
+  Value *RHS = II->getOperand(1);
+  
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS, "cmp");
+  Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+  
+  // Update PHI nodes in the destination blocks.
+  // Replace all incoming values from the switch's parent with undef.
+  for (auto BBI = TrueDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    PHINode *PN = cast<PHINode>(BBI);
+    while (PN->getBasicBlockIndex(SI->getParent()) != -1)
+      PN->removeIncomingValue(SI->getParent(), false);
+    PN->addIncoming(UndefValue::get(LHS->getType()), SI->getParent());
+  }
+  for (auto BBI = FalseDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    PHINode *PN = cast<PHINode>(BBI);
+    while (PN->getBasicBlockIndex(SI->getParent()) != -1)
+      PN->removeIncomingValue(SI->getParent(), false);
+    PN->addIncoming(UndefValue::get(LHS->getType()), SI->getParent());
+  }
+  SI->eraseFromParent();
+  return true;
+}
+
+
+
 /// Compute masked bits for the condition of a switch
 /// and use it to remove dead cases.
 static bool eliminateDeadSwitchCases(SwitchInst *SI, DomTreeUpdater *DTU,
@@ -7156,6 +7300,10 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
+  // Try to simplify switch on cmp intrinsic (ucmp/scmp) to icmp.
+  if (simplifySwitchOnCmpIntrinsic(SI, Builder))
+    return requestResimplify();
+
   if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
     return requestResimplify();

